import grpc
from envoy_external_authorization import CheckRequest, CheckResponse

class ExternalAuthorizationService(grpc.Servicer):
    def Check(self, request, context):
        # Accept custom headers from requests and make authorization decisions
        custom_headers = request.custom_headers
        if "Authorization" in custom_headers:
            auth_header = custom_headers["Authorization"]
            if auth_header == "Bearer <token>":
                return CheckResponse(status=CheckStatus.OK)
            else:
                return CheckResponse(status=CheckStatus.UNAUTHORIZED)
        else:
            return CheckResponse(status=CheckStatus.UNAUTHORIZED)